import loader from '@monaco-editor/loader';
import markdownit from 'markdown-it';
import {sanitizeHtml} from 'safevalues';
import {setElementInnerHtml} from 'safevalues/dom';
import Sortable from 'sortablejs';
import { GoogleGenAI, Modality } from "@google/genai";

interface MarkdownItInstance {
  render: (markdown: string) => string;
}

let monaco: any;
type MonacoEditorInstance = any;

const NOTEBOOK_CONTAINER = document.getElementById('notebook') as HTMLDivElement;
const md: MarkdownItInstance = (markdownit as any)({ html: true, linkify: true, typographer: true });

let cellCounter = 0;
const cells: Cell[] = [];
const monacoInstances: {[key: string]: MonacoEditorInstance} = {};
const persistentScope: Record<string, any> = {};

interface Cell {
  id: string;
  type: 'js' | 'md';
  mode?: 'edit' | 'render';
  outputs: any[];
}

// AI Utility: Raw PCM Encoding/Decoding for Live API
const audioUtils = {
  encode(bytes: Uint8Array): string {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  },
  decode(base64: string): Uint8Array {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  },
  async decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate = 24000, numChannels = 1): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  }
};

// High-level webmodel helper
const webmodel = {
  audioUtils,
  async getCamera(videoElement?: HTMLVideoElement) {
    const stream = await navigator.mediaDevices.getUserMedia({ video: true });
    if (videoElement) {
      videoElement.srcObject = stream;
      await videoElement.play();
    }
    return stream;
  },
  async getMicrophone() {
    return await navigator.mediaDevices.getUserMedia({ audio: true });
  },
  voiceRecognition(onResult: (text: string) => void) {
    const Recognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!Recognition) {
      console.warn("Speech recognition not supported in this browser.");
      return null;
    }
    const rec = new Recognition();
    rec.continuous = true;
    rec.interimResults = false;
    rec.onresult = (e: any) => {
      const text = e.results[e.results.length - 1][0].transcript;
      onResult(text);
    };
    rec.start();
    return rec;
  },
  async speak(text: string, voiceName: string = 'Kore') {
    const ai = new GoogleGenAI({ apiKey: (process.env as any).API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName } },
        },
      },
    });
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const buffer = await audioUtils.decodeAudioData(audioUtils.decode(base64Audio), ctx);
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.start();
      return new Promise((resolve) => source.onended = resolve);
    }
  }
};

function renderOutputs(outputDiv: HTMLElement, outputs: any[]) {
  let outputHtml = '';
  outputs.forEach((output) => {
    if (output.type === 'log') {
      outputHtml += `<div class="console-log">${md.render(output.data)}</div>`;
    } else if (output.type === 'error') {
      outputHtml += `<div class="console-error">Error: ${output.data}</div>`;
    } else if (output.type === 'image') {
      const src = output.data.startsWith('data:') ? output.data : `data:${output.mime};base64,${output.data}`;
      outputHtml += `<img src="${src}" style="max-width:100%; border-radius:8px; margin-top:10px;" />`;
    } else if (output.type === 'html') {
      outputHtml += `<div>${output.data}</div>`;
    }
  });
  setElementInnerHtml(outputDiv, sanitizeHtml(outputHtml));
}

async function runCell(cellId: string) {
  const cell = cells.find(c => c.id === cellId);
  const editor = monacoInstances[cellId];
  if (!cell || !editor) return;

  const outputDiv = document.getElementById(`${cellId}_output`) as HTMLDivElement;
  const editorContainer = document.getElementById(`${cellId}_editor_container`) as HTMLDivElement;
  const code = editor.getValue();

  if (cell.type === 'md') {
    if (cell.mode === 'edit') {
      setElementInnerHtml(outputDiv, sanitizeHtml(md.render(code)));
      outputDiv.style.display = 'block';
      editorContainer.style.display = 'none';
      cell.mode = 'render';
    } else {
      outputDiv.style.display = 'none';
      editorContainer.style.display = 'block';
      cell.mode = 'edit';
      editor.focus();
    }
    return;
  }

  setElementInnerHtml(outputDiv, '');
  cell.outputs = [];
  outputDiv.style.display = 'block';

  const consoleProxy = {
    log: (...args: any[]) => {
      const text = args.map(a => typeof a === 'object' ? JSON.stringify(a, null, 2) : String(a)).join(' ');
